sql:
SELECT AVG(JULIANDAY(date_completed) - JULIANDAY(date_started)) AS average_duration
FROM experiments
WHERE model_name = 'ResNet-50';

SELECT model_name, AVG(strftime('%J', date_completed) - strftime('%J', date_started)) AS average_duration_days
FROM experiments
GROUP BY model_name;

SELECT model_name, date_completed
FROM experiments
ORDER BY date_completed DESC;

SELECT COUNT(experiment_id) AS total_experiments
FROM experiments
WHERE date_started LIKE '2023-10-%';

SELECT COUNT(DISTINCT experiment_id) AS total_experiments
FROM access_logs
WHERE user_id = 123;

SELECT COUNT(experiment_id) AS total_experiments_viewed
FROM access_logs
WHERE user_id = 1 AND access_type = 'view';

SELECT AVG(JULIANDAY(e.date_completed) - JULIANDAY(e.date_started)) AS average_duration
FROM experiments e
INNER JOIN training_sessions s ON e.experiment_id = s.experiment_id;

SELECT experiment_id, model_name, date_started, date_completed
FROM experiments
ORDER BY date_started DESC;

SELECT experiment_id, model_name, date_completed
FROM experiments
ORDER BY date_completed DESC;

SELECT experiment_id
FROM experiments
ORDER BY experiment_id;

SELECT AVG(feedback_rating) AS average_rating
FROM feedback
WHERE experiment_id = 123;

external_knowledge:
- "Identities of the participants" refers to the unique identifiers of users (`user_id`).;
- "Last interacted with any project" indicates the most recent access date per user for each experiment in the `access_logs` table.;
- "Sorted in the usual manner" means sorting the results based on `user_id` in ascending order.
